void writeBMPFile(const char* filename, unsigned char* pixels, int width, int height) {
    FILE* fp = fopen(filename, "wb");
    if (!fp) {
        printf("Failed to open file for writing: %s\n", filename);
        return;
    }

    int filesize = 54 + 3 * width * height;

