    header.y_resolution_ppm = 0;
    header.num_colors = 0;
    header.important_colors = 0;

    fwrite(&header.type, 1, 2, fp);
    fwrite(&header.size, 1, 4, fp);
    fwrite(&header.reserved1, 1, 2, fp);
    fwrite(&header.reserved2, 1, 2, fp);
    fwrite(&header.offset, 1, 4, fp);
    fwrite(&header.dib_header_size, 1, 4, fp);
    fwrite(&header.width_px, 1, 4, fp);
    fwrite(&header.height_px, 1, 4, fp);
    fwrite(&header.num_planes, 1, 2, fp);
    fwrite(&header.bits_per_pixel, 1, 2, fp);
    fwrite(&header.compression, 1, 4, fp);
    fwrite(&header.image_size_bytes, 1, 4, fp);
    fwrite(&header.x_resolution_ppm, 1, 4, fp);
    fwrite(&header.y_resolution_ppm, 1, 4, fp);
    fwrite(&header.num_colors, 1, 4, fp);
    fwrite(&header.important_colors, 1, 4, fp);

    // Write pixel data
    for (int y = height - 1; y >= 0; y--) {
        for (int x = 0; x < width; x++) {
            unsigned char pixel[3];
            pixel[0] = pixels[y * width + x];  // Blue
            pixel[1] = pixels[y * width + x];  // Green
            pixel[2] = pixels[y * width + x];  // Red
            fwrite(pixel, 1, 3, fp);
        }

        // Pad row to multiple of 4 bytes
        int padding = (4 - (width * 3) % 4) % 4;
        for (int i = 0; i < padding; i++) {
            fputc(0, fp);
        }
    }

